// AMRIGS - Prova AMB, AMRIGS, ACM e AMMS 01/2025 - Acesso Direto e Autoavaliação
// Gabarito definitivo (pós-recursos), conforme Edital nº 18/2025 - Anexo II
export const AMRIGS_2025_QUESTIONS: any[] = [
  { id: "amrigs_2025_001", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Considerando as características das cefaleias, relacione a Coluna 1 (1. Migrânea; 2. Cefaleia tipo tensional; 3. Cefaleias trigêmino-autonômicas; 4. Cefaleia em salvas) à Coluna 2: (Cefaleia isenta de manifestações associadas, como vômito, latejamento ou agravamento com movimentos.) (Dor profunda, retro-orbital, intensidade excruciante, não flutuante e de característica explosiva.) (Crises repetidas de cefaleia, unilateral e latejante, com duração de 4 a 72 horas em pacientes com exame físico normal.) A ordem correta, de cima para baixo, é:", options: ["4 – 1 – 2.", "3 – 4 – 1.", "2 – 4 – 1.", "2 – 3 – 4."], correctIndex: 2 },
  { id: "amrigs_2025_002", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Em relação ao delirium, analise: I. Suas principais características são o déficit de atenção e o distúrbio de consciência. II. É um estado de confusão mental e comportamental de redução da compreensão, coerência e da capacidade de raciocínio, com meses de evolução. III. O clonazepam é o fármaco de escolha para a promoção do sono em pacientes com delirium hiperativo, devido à facilidade de administração e ao baixo risco de eventos adversos. Quais estão corretas?", options: ["Apenas I.", "Apenas III.", "Apenas II e III.", "I, II e III."], correctIndex: 0 },
  { id: "amrigs_2025_003", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Em relação à influenza A, assinale a alternativa correta.", options: ["A transmissibilidade e virulência das cepas virais são bastante previsíveis, o que faz com que não ocorram pandemias em decorrência da influenza A.", "A implementação de medidas de isolamento e a restrição de viagens ocorridas durante a pandemia de covid-19 não reduziram a circulação do vírus da influenza A na população.", "A plasticidade e a segmentação dos seus genomas e seu extenso reservatório em mamíferos e aves potencializam o seu risco de causar uma pandemia.", "A vacinação em massa não se mostrou efetiva para a prevenção de infecção por influenza A."], correctIndex: 2 },
  { id: "amrigs_2025_004", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "Em relação à aferição da pressão arterial, analise: I. O uso inapropriado de manguito pequeno subestima o valor da pressão arterial. II. Definem-se as pressões sistólica e diastólica, respectivamente, com o primeiro e o quinto sons de Korotkoff. III. Em geral, o valor da pressão sistólica aumenta e o valor da diastólica diminui quando a aferição é feita em artérias mais distais. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 2 },
  { id: "amrigs_2025_005", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "O gráfico abaixo apresenta o perfil farmacocinético de três diferentes tipos de insulina para o tratamento do diabetes: a insulina A tem pico rápido e curto, a insulina B tem pico intermediário mais lento, e a insulina C não tem pico definido (perfil basal prolongado). As insulinas correspondentes às letras A, B e C, respectivamente, são:", options: ["Glargina – NPH – regular.", "Lispro – glargina – regular.", "NPH – degludeca – lispro.", "Lispro – NPH – glargina."], correctIndex: 3 },
  { id: "amrigs_2025_006", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "Sobre a infecção urinária, é correto afirmar que:", options: ["Mulheres com suspeita de cistite não complicada devem realizar cultura de urina para direcionar o tratamento conforme o perfil de sensibilidade antimicrobiano.", "Homens com sintomas de cistite podem receber tratamento empírico, sem necessidade de exame de cultura adicional.", "O critério microbiológico para diagnóstico de bacteriúria assintomática é a presença de mais de 10.000 unidades formadoras de colônia/ml de bactérias na urina.", "Apenas membros da família Enterobacteriaceae convertem o nitrato em nitrito na urina."], correctIndex: 3 },
  { id: "amrigs_2025_007", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "São fatores que contribuem para a falência orgânica na sepse os seguintes, EXCETO:", options: ["Resposta inflamatória aberrante com dano celular.", "Disfunção do endotélio vascular da microcirculação.", "Disfunção mitocondrial devido a estresse oxidativo.", "Redução da produção de oxido nítrico, provocando colapso vasomotor."], correctIndex: 3 },
  { id: "amrigs_2025_008", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Em relação à crise renal esclerodérmica, assinale a alternativa correta.", options: ["A presença de anticorpo anticentrômero sinaliza um alto risco para crise renal esclerodérmica.", "A droga de escolha para o tratamento da crise são os inibidores da enzima de conversão da angiotensina.", "A crise hipertensiva faz parte da abertura do quadro em todos os pacientes.", "O exame de urina mostra proteinúria maciça e hematúria macroscópica."], correctIndex: 1 },
  { id: "amrigs_2025_009", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Hematologia", text: "A respeito da anemia, analise: I. A anemia associada a aumento na produção de reticulócitos, após ajuste para o grau de anemia, sugere ocorrência de perda de sangue ou hemólise. II. Deficiência de ferro ou de folato são situações em que, na presença de sangramento ou hemólise, pode não haver uma resposta apropriada dos reticulócitos. III. O percentual de reticulócitos representa a porcentagem de eritrócitos que são reticulócitos, e não é necessário ajuste em relação ao grau de anemia para sua interpretação. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 0 },
  { id: "amrigs_2025_010", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Em relação aos tumores secretores de catecolaminas, analise: I. Ocorrem em igual frequência entre homens e mulheres, principalmente na terceira, quarta e quinta décadas de vida. II. Os anti-hipertensivos e hipoglicemiantes orais podem aumentar os níveis mensurados de catecolaminas e metanefrinas, podendo provocar resultados falso-positivos. III. A excreção urinária de 24 horas de catecolaminas e metanefrinas fracionadas ou a determinação dos níveis plasmáticos de metanefrinas fracionadas devem ser verificadas anualmente, durante toda a vida dos pacientes que tiveram diagnóstico e foram tratados. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 1 },
  { id: "amrigs_2025_011", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Clínica Médica", text: "Relacione a Coluna 1 (1. Colestiramina; 2. Omeprazol; 3. Isoniazida; 4. Penicilamina) à Coluna 2, associando cada medicamento ao nutriente com níveis adversamente alterados quando do seu uso: (Zinco.) (Vitamina B12.) (Vitamina D.) (Piridoxina.) A ordem correta, de cima para baixo, é:", options: ["1 – 2 – 3 – 4.", "2 – 4 – 1 – 3.", "4 – 1 – 3 – 2.", "4 – 2 – 1 – 3."], correctIndex: 3 },
  { id: "amrigs_2025_012", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Sobre o diabetes insipidus, é correto afirmar que:", options: ["O diabetes insipidus nefrogênico é causado pela incapacidade do hipotálamo de secretar vasopressina para atuar sobre um rim normal.", "A polidipsia primária é um distúrbio causado pela ausência primária de produção de vasopressina.", "Níveis de ácido úrico superiores a 5mg/dL podem ajudar a diferenciar o diabetes insipidus de polidipsia primária.", "O diabetes insipidus nefrogênico ocorre comumente em pacientes com isquemia cerebral grave e pode indicar morte encefálica."], correctIndex: 2 },
  { id: "amrigs_2025_013", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Sobre as crioglobulinemias, analise: I. As do tipo I são monoclonais, não têm atividade do fator reumatoide e estão associadas a neoplasias malignas hematopoiéticas, como o mieloma. II. As dos tipos II e III podem estar relacionadas à vasculite sistêmica, envolvendo vasos de pequeno calibre. III. A infecção pelo vírus da hepatite B é responsável por pelo menos 80% dos casos de vasculite associada à crioglobulina mista. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 0 },
  { id: "amrigs_2025_014", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Em relação ao sarampo, analise: I. O tratamento é, em grande parte, de suporte, com administração de vitamina A e antibiótico para combate do agente causador da doença. II. A resposta imune do hospedeiro ao vírus do sarampo é essencial para a eliminação viral e recuperação clínica. III. A resposta da IgM está ausente após reexposição ou revacinação e serve como marcador de infecção primária. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 2 },
  { id: "amrigs_2025_015", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Em relação à dengue, analise: I. Na febre hemorrágica da dengue, a trombocitopenia com plaquetas abaixo de 100.000 células/ml e alargamento do tempo de protrombina são característicos. II. A leucopenia desenvolve-se no segundo dia de febre, caindo para 1.000 a 2.000 células/ml no quinto ou sexto dia. III. O anticorpo IgM surge de 3 a 5 dias após a infecção, e o IgG, de 9 a 10 dias após. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 3 },
  { id: "amrigs_2025_016", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Em relação ao Acidente Vascular Cerebral (AVC), é correto afirmar que:", options: ["Pressão arterial superior a 185/110mmHg, a despeito do tratamento, não é contraindicação à trombólise.", "O ácido acetilsalicílico é o único agente antiplaquetário que se mostrou eficaz no tratamento agudo do acidente vascular cerebral isquêmico.", "A anticoagulação de rotina faz parte do tratamento primário da isquemia cerebral aterotrombótica.", "A combinação de ácido acetilsalicílico e clopidogrel após um AVC minor não se mostrou benéfica na prevenção de um segundo AVC."], correctIndex: 1 },
  { id: "amrigs_2025_017", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Sobre a doença hepática gordurosa não alcoólica, assinale a alternativa correta.", options: ["Ao contrário da doença hepática alcoólica, os níveis de ALT são mais elevados do que os níveis de AST, tendo importância prognóstica.", "Elevação discreta da ferritina e resultados positivos para anticorpo antinuclear e anticorpo antimúsculo liso são comuns quando do diagnóstico.", "Pacientes com cirrose induzida por hepatite não alcoólica não têm risco de evoluir para hepatocarcinoma.", "A presença de vírus da hepatite B ou C não interfere nos critérios diagnósticos para doença hepática gordurosa não alcoólica."], correctIndex: 1 },
  { id: "amrigs_2025_018", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Qual das alternativas abaixo indica uma doença pulmonar intersticial que geralmente apresenta boa resposta clínica ao uso de corticoide sistêmico isoladamente?", options: ["Pneumoconiose.", "Asbestose.", "Sarcoidose.", "Fibrose pulmonar crônica por radiação."], correctIndex: 2 },
  { id: "amrigs_2025_019", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Homem, 75 anos, declínio cognitivo progressivo há mais de um ano, com dificuldade de planejamento, atenção, capacidade visuoespacial, com memória relativamente preservada. Relata visões recorrentes vívidas e bem definidas, sonolência e desorientação intercaladas com lucidez. Há dois meses, passou a andar devagar, com passos curtos, postura encurvada e quedas. Piora acentuada de rigidez/tremores após introdução de risperidona. Anos antes, já apresentava episódios noturnos sugestivos de transtorno comportamental do sono REM. Diagnóstico mais provável:", options: ["Transtorno neurocognitivo maior devido à doença de Alzheimer.", "Transtorno neurocognitivo maior devido à doença de Parkinson.", "Transtorno neurocognitivo maior com corpos de Lewy.", "Delirium induzido por antipsicótico em paciente idoso."], correctIndex: 2 },
  { id: "amrigs_2025_020", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Psiquiatria", text: "Homem, 28 anos, agitação extrema, taquicardia, sudorese profusa, PA 180/110mmHg, midríase, alucinações visuais e pensamentos paranoides após consumo de cocaína cerca de uma hora antes. Tremores, náuseas e dificuldade de fala. Sem febre ou trauma. Assinale a alternativa correta.", options: ["Os usuários de cocaína têm menor risco de apresentar distonia aguda induzida por antipsicóticos.", "Para controle da hipertensão, é indicado utilizar propranolol.", "Quando há riscos de heteroagressão, em que a via parenteral será necessária, diazepam intramuscular é a medicação de escolha.", "Devido às propriedades depressoras, por ação GABAérgica, os benzodiazepínicos são a primeira escolha, buscando antagonizar os efeitos estimulantes da cocaína."], correctIndex: 3 },
  { id: "amrigs_2025_021", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Analise as assertivas a seguir sobre a anatomia das hérnias inguinais: I. O triângulo de Hesselbach é delimitado medialmente pela borda lateral do músculo reto abdominal, lateralmente pelos vasos epigástricos inferiores e inferiormente pelo ligamento inguinal. II. O nervo genitofemoral divide-se em dois ramos, sendo que o ramo genital acompanha o funículo espermático através do anel inguinal profundo e, eventualmente, é lesado durante hernioplastias. III. Hérnias inguinais indiretas, em geral, localizam-se medialmente aos vasos epigástricos inferiores e penetram no canal inguinal através de um defeito adquirido na parede posterior. IV. O tendão conjunto é formado pela união das fibras do músculo oblíquo interno e transverso do abdome, reforçando a parede posterior do canal inguinal. Quais estão corretas?", options: ["Apenas I e IV.", "Apenas II e III.", "Apenas II e IV.", "Apenas I, II e IV."], correctIndex: 3 },
  { id: "amrigs_2025_022", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "A respeito da anatomia cirúrgica da região cervical, analise: I. A artéria tireóidea inferior se origina do tronco tireocervical, que é ramo da artéria subclávia. II. A artéria tireóidea superior se origina da artéria carótida interna. III. O nervo laríngeo recorrente direito passa por baixo do ligamento arterioso no arco aórtico e segue no sulco traqueoesofágico até atingir a tireoide. Quais estão corretas?", options: ["Apenas I.", "Apenas II.", "Apenas III.", "Apenas II e III."], correctIndex: 0 },
  { id: "amrigs_2025_023", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher, 42 anos, assintomática, ecografia identifica nódulo de 4cm no lobo direito do fígado. TC e RM de abdome mostram lesão de 4,2cm, hipervascularizada, com cicatriz fibrosa central e septos radiados. Qual é a melhor conduta no caso?", options: ["Solicitar uma cintilografia com hemácias marcadas.", "Proceder à punção biópsia com agulha fina para esclarecer o diagnóstico.", "Manter a conduta expectante é o mais apropriado, visto que a paciente está assintomática.", "Indicar cirurgia de ressecção para evitar complicações futuras."], correctIndex: 2 },
  { id: "amrigs_2025_024", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 70 anos, previamente assintomático, dor em fossa ilíaca esquerda, febre e leucocitose. TC de abdome mostra espessamento na topografia do cólon sigmoide, compatível com diverticulite aguda não complicada. Assinale a melhor conduta.", options: ["O tratamento inicial deve ser clínico, com analgésicos, modificação na dieta e antibióticos.", "Colonoscopia deve ser indicada na avaliação inicial, para descartar a presença de neoplasia maligna.", "Deve ser indicada cirurgia, pois a recorrência de crises é muito elevada apenas com o tratamento clínico.", "Nos casos em que for indicada a cirurgia, deve ser realizada colostomia para diminuir o índice de complicações do procedimento."], correctIndex: 0 },
  { id: "amrigs_2025_025", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 65 anos, abaulamento em região umbilical há cerca de 1 ano. Há 24 horas, dor intensa no local, sem evacuar/eliminar flatos há 48 horas, dois episódios de vômitos fétidos. Hérnia umbilical com hiperemia local, não redutível e dolorosa. Analise: I. O quadro sugere hérnia encarcerada complicada por estrangulamento. II. A conduta inicial indicada é a tentativa de redução manual do conteúdo da hérnia. III. Em caso de indicação cirúrgica, herniorrafia com tela é a melhor alternativa. Quais estão corretas?", options: ["Apenas I.", "Apenas II.", "Apenas III.", "Apenas I e III."], correctIndex: 0 },
  { id: "amrigs_2025_026", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "O abdome agudo é uma das condições mais relevantes no atendimento de emergência. Assinale a alternativa correta.", options: ["A dor visceral é tipicamente bem delimitada, e o paciente, em geral, consegue apontar com exatidão o local de maior intensidade dolorosa.", "O sinal de chandelier corresponde a uma vesícula biliar distendida e palpável, acompanhada de icterícia obstrutiva, achado típico de tumores periampulares.", "No contexto do abdome agudo, a laparoscopia diagnóstica pode auxiliar tanto no diagnóstico quanto na conduta terapêutica. Todavia, a presença de distensão intestinal significativa constitui contraindicação absoluta à sua realização.", "A apendicite aguda constitui a causa mais frequente de abdome agudo não obstétrico durante a gestação."], correctIndex: 3 },
  { id: "amrigs_2025_027", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Gestante de 30 semanas, G1P0, dor abdominal de início súbito, migrando do mesogástrio para o flanco direito, náuseas, febre não aferida. FC 118bpm, dor à palpação em flanco/lombar direito, sem sinais claros de irritação peritoneal. USG inconclusivo para apendicite, sem sinais de sofrimento fetal. Leucócitos 13.500/mm³ e PCR elevada. Hospital sem ressonância magnética. Qual conduta é mais adequada?", options: ["Realizar TC abdominal, utilizando protocolo de dose mínima de radiação, visando esclarecer o diagnóstico.", "Indicar cirurgia imediatamente, com base nos achados clínico-laboratoriais, pois o atraso pode aumentar risco fetal.", "Repetir o ultrassom seriado enquanto se aguarda melhora clínica, pois a exposição à radiação na gestação é proibitiva.", "Iniciar antibiótico empírico e observar a paciente, evitando exame adicional."], correctIndex: 0 },
  { id: "amrigs_2025_028", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 55 anos, sobrepeso, pirose retroesternal diária há 8 anos, regurgitação ácida ocasional, desconforto pós-prandial, sintomas persistentes apesar de IBP intermitente. EDA evidencia metaplasia intestinal no epitélio esofágico distal, diagnóstico de Esôfago de Barrett (EB). Analise: I. Ocorre como consequência do refluxo ácido, não sendo observado em casos de refluxo alcalino. II. A identificação do EB constitui indicação absoluta para a realização de cirurgia antirrefluxo. III. Pode ser classificado, conforme sua extensão, em longo (≥3cm) ou curto (<3cm). Quais estão corretas?", options: ["Apenas I.", "Apenas III.", "Apenas I e II.", "Apenas II e III."], correctIndex: 1 },
  { id: "amrigs_2025_029", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher, 45 anos, dor abdominal intensa no quadrante inferior esquerdo há 48 horas, febre baixa (37,9°C), sensibilidade FIE, leucocitose leve (11.500/mm³). TC: diverticulite sigmoide com espessamento parietal, inflamação da gordura pericólica e pequenas bolhas de ar pericólicas (<5cm), sem abscesso ou líquido livre. Estável, tolerando dieta oral. Qual conduta é mais apropriada?", options: ["Iniciar antibioticoterapia intravenosa de amplo espectro, manter a paciente em dieta zero e monitorizar a evolução clínica.", "Prescrever antibioticoterapia oral com cobertura para Gram-negativos e anaeróbios, associada à dieta líquida restrita e repouso no leito.", "Optar por tratamento sintomático com analgésicos e dieta oral liberada, sem antibioticoterapia, e reavaliar em 24-48 horas.", "Considerar tratamento não operatório, avaliar nível de PCR e monitorizar a evolução clínica."], correctIndex: 3 },
  { id: "amrigs_2025_030", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Sobre o câncer de esôfago, analise: I. O adenocarcinoma esofágico é de 3 a 4 vezes mais prevalente em homens, e a incidência é significativamente maior entre afro-americanos, mesmo após ajuste para fatores socioeconômicos e consumo de tabaco/álcool. II. Estudos recentes demonstram que a associação entre HPV e carcinoma espinocelular de esôfago é amplamente prevalente, com impacto prognóstico e terapêutico bem estabelecido na prática clínica. III. A duração dos sintomas de DRGE está associada ao risco de desenvolvimento de adenocarcinoma esofágico, porém a frequência desses sintomas não apresenta correlação significativa com tal risco. Quais estão INCORRETAS?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 3 },
  { id: "amrigs_2025_031", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "A respeito da fisiopatologia e dos fatores de risco para pancreatite aguda, analise: I. A ingestão alcoólica é a segunda causa mais frequente de pancreatite aguda. O risco da doença é reduzido em indivíduos que consomem álcool e também são tabagistas, devido a um efeito anti-inflamatório do tabaco. II. A pancreatite aguda é a complicação mais comum após CPRE, ocorrendo com maior frequência em mulheres e, na maioria dos casos, tendo apresentação clínica branda. III. A principal causa de pancreatite aguda no Ocidente é a litíase biliar, sendo mulheres de 50 a 70 anos a população mais afetada. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 2 },
  { id: "amrigs_2025_032", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Acerca dos distúrbios motores do esôfago, assinale a alternativa correta.", options: ["O esôfago em quebra-nozes (ou esôfago hipercontrátil) é uma patologia que acomete homens e mulheres em proporções semelhantes. Trata-se do distúrbio de hipermotilidade esofágica mais comum.", "O espasmo esofágico difuso é mais frequente em mulheres, com alterações motoras predominando nos terços proximal e médio.", "A tríade clássica de sintomas da acalásia inclui disfagia, dor torácica e perda ponderal.", "A acalásia é considerada uma condição pré-maligna. Ao longo de 20 anos, pacientes apresentam risco entre 18 e 20% de desenvolver neoplasia maligna."], correctIndex: 0 },
  { id: "amrigs_2025_033", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 28 anos, vítima de acidente automobilístico com instabilidade hemodinâmica, gasometria com pH 7,15, BE -12, lactato 4,8, T 34,2°C, FAST positivo. Após ressuscitação inicial mantém instabilidade. Laparotomia: hemoperitônio, laceração hepática grau IV, lesão esplênica grau III, laceração jejunal, avulsão do mesossigmoide com contaminação fecal. Assinale a alternativa correta.", options: ["A tromboelastografia é capaz de identificar trombocitopenia e hiperfibrinólise, permitindo direcionar a reposição de hemoderivados, porém o tempo necessário até o resultado não permite seu uso no atendimento inicial.", "O ácido tranexâmico é um inibidor da fibrinólise e administrá-lo precocemente está associado à redução da mortalidade por sangramento sem aumentar significativamente o risco de eventos tromboembólicos.", "Na cirurgia de urgência, a conduta indicada consiste em rafia do parênquima hepático, esplenectomia, ressecção do segmento jejunal lacerado com enteroanastomose e ressecção do sigmoide com anastomose primária.", "A expansão volêmica com solução cristaloide está indicada no transoperatório, enquanto se aguardam resultados de hemograma e coagulograma para decisão sobre nova transfusão de sangue e hemoderivados."], correctIndex: 1 },
  { id: "amrigs_2025_034", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 58 anos, dor abdominal difusa 24h, náuseas/vômitos biliosos, parada de eliminação de gases (12h) e fezes (24h). Cirurgias prévias (laparotomia por trauma, apendicectomia). Abdome distendido, dor difusa periumbilical, sem irritação peritoneal. TC: segmento de jejuno distal dilatado entre dois pontos de estreitamento, redução do realce parietal pelo contraste, ausência de pneumoperitônio. Qual é a conduta terapêutica mais indicada?", options: ["Proceder à abordagem cirúrgica.", "Indicar nada por via oral (NPO), hidratação, sonda nasogástrica e manter conduta expectante.", "Solicitar exame contrastado de trânsito do intestino delgado.", "Efetuar dosagem de lactato, gasometria arterial e LDH."], correctIndex: 0 },
  { id: "amrigs_2025_035", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Sobre a obesidade mórbida, analise: I. Doença renal terminal está associada à obesidade mórbida. II. Obesidade mórbida está associada ao risco de câncer de próstata. III. A alteração mais frequente em obesos mórbidos é artrite com doença articular degenerativa. IV. Alterações epigenéticas são frequentes no desenvolvimento da obesidade mórbida. Quais estão corretas?", options: ["Apenas I e IV.", "Apenas II e III.", "Apenas I, II e III.", "I, II, III e IV."], correctIndex: 3 },
  { id: "amrigs_2025_036", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 42 anos, pancreatite aguda biliar grave com internação em UTI, 6 semanas após inicia dor epigástrica/HCE persistente, saciedade precoce, náuseas, perda de 6kg. TC: lesão bem delimitada de 8cm no corpo/cauda do pâncreas, conteúdo heterogêneo (líquido+sólido), parede bem definida com realce, atrofia do parênquima adjacente. Assinale o diagnóstico correto.", options: ["Necrose pancreática isolada.", "Pseudocisto pancreático.", "Coleção líquida aguda peripancreática.", "Abscesso pancreático."], correctIndex: 0 },
  { id: "amrigs_2025_037", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher, 42 anos, fraqueza generalizada, náuseas, vômitos persistentes, diminuição da ingestão alimentar progressiva 3 dias, diplopia ocular, nistagmo, vertigem rotatória, anormalidades da marcha, delirium e déficit de memória recente. Bypass gástrico há 3 anos. Glicemia capilar 122mg/dL. Qual é o diagnóstico mais provável?", options: ["Deficiência de tiamina.", "Choque hipovolêmico.", "Suboclusão intestinal.", "Hiponatremia."], correctIndex: 0 },
  { id: "amrigs_2025_038", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "De acordo com o checklist de cirurgia segura proposto pela Organização Mundial de Saúde (OMS), qual dos itens a seguir faz parte da etapa de time-out?", options: ["Avaliação de via aérea difícil.", "Medição da PA.", "Contagem de compressas utilizadas.", "Confirmação do procedimento."], correctIndex: 3 },
  { id: "amrigs_2025_040", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Homem, 32 anos, vítima de acidente automobilístico com trauma abdominal contuso e fratura de pelve, laparotomia de urgência (rafia hepática e esplenectomia), fixação externa da pelve. Após 18 horas, sedado, em VM com aumento da pressão inspiratória, débito urinário 15ml/h, uso de noradrenalina, acidose metabólica, lactato 4,2mmol/L, pressão intra-abdominal de 36cmH2O (26,5mmHg). Qual é a medida indicada no caso?", options: ["Iniciar protocolo de transfusão maciça (1:1:1).", "Administrar manitol 20%, EV.", "Administrar solução salina hipertônica, EV.", "Proceder à laparotomia."], correctIndex: 3 },
  { id: "amrigs_2025_041", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 28 anos, nulípara, nódulo palpável em mama direita há 3 meses, móvel, fibroelástico, medindo 2,5x1,3x2,0cm, limites regulares, indolor. USG: tumor ovalado, orientação paralela à pele, bem definido, margens delimitadas, hipoecogênico. Qual é a conduta mais adequada?", options: ["Exérese cirúrgica imediata com margem de segurança.", "Biópsia por agulha grossa (core biopsy) para confirmação histológica.", "Acompanhamento semestral com ultrassonografia.", "Mamografia bilateral para avaliação complementar."], correctIndex: 2 },
  { id: "amrigs_2025_042", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 19 anos, cólicas menstruais intensas desde a menarca aos 12 anos, cíclica, iniciando um dia antes do fluxo e persistindo nos dois primeiros dias, impedindo atividades, não progressiva. Nega dispareunia, SUA ou outros sintomas ginecológicos. Exame físico sem alterações. Diagnóstico mais provável e conduta inicial mais adequada, respectivamente:", options: ["Dismenorreia secundária – solicitar ultrassonografia pélvica e prescrever analgésicos opioides.", "Dismenorreia primária – orientar medidas de higiene menstrual e prescrever anti-inflamatórios não esteroides (AINEs).", "Endometriose – indicar laparoscopia diagnóstica e terapêutica e prescrever AINEs.", "Doença inflamatória pélvica – iniciar antibioticoterapia de amplo espectro e solicitar exames para pesquisa de clamídia e gonococo."], correctIndex: 1 },
  { id: "amrigs_2025_043", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 26 anos, previamente saudável, disúria, aumento da frequência miccional e dor suprapúbica há 2 dias. Nega febre, calafrios ou dor lombar. Relações sexuais há 3 dias. Sem sinais de corrimento vaginal ou irritação vulvar. Sedimento urinário: leucocitúria e nitritos positivos. Diagnóstico e conduta mais prováveis, respectivamente:", options: ["Cistite aguda – iniciar nitrofurantoína por 5 dias.", "Vulvovaginite – solicitar cultura de secreção vaginal e iniciar tratamento antifúngico.", "Uretrite – solicitar cultura de secreção vaginal e uretral e iniciar azitromicina.", "Síndrome da bexiga dolorosa – solicitar exame de urina, urocultura e cistoscopia."], correctIndex: 0 },
  { id: "amrigs_2025_044", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Casal, ambos com 35 anos, infertilidade conjugal. Mulher com ciclos regulares, fluxo reduzido. Espermograma: normozoospermia. USTV: ovários normais, sem SOP, útero com cavidade normal. Progesterona 10ng/ml (fase lútea >3ng/ml), realizada 7 dias antes da menstruação esperada. HSG: patência tubária bilateral. Assinale V ou F: ( ) A paciente apresenta evidências de ovulação. ( ) A HSG é o exame padrão-ouro para avaliação da cavidade uterina. ( ) A USTV pode avaliar a reserva ovariana. ( ) A presença de normozoospermia no espermograma não exclui a necessidade de avaliação hormonal no homem. A ordem correta, de cima para baixo, é:", options: ["V – F – V – F.", "V – F – F – V.", "F – V – F – V.", "F – V – V – F."], correctIndex: 0 },
  { id: "amrigs_2025_045", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 28 anos, saudável, Sangramento Uterino Anormal (SUA) persistente há 2 meses, desde que iniciou pílula combinada (etinilestradiol 20mcg + levonorgestrel 100mcg). Uso correto, sem esquecimentos, sem outros sintomas. Nega tabagismo, parceiro fixo há 1 ano. Especular normal, citologia oncótica em dia e sem alterações. Qual é a conduta inicial mais adequada?", options: ["Realizar USTV para investigar causas estruturais e prescrever AINEs para controle do sangramento.", "Suspender o uso da pílula combinada, prescrever anticoncepcional contendo apenas progesterona e agendar histeroscopia diagnóstica.", "Orientar a paciente sobre a possibilidade de adaptação do organismo nos primeiros meses de uso da pílula, reforçar a importância da adesão correta e agendar reavaliação em 2 meses.", "Prescrever doxiciclina 100mg/dia profilática, realizar teste de gravidez e solicitar exames para rastreio de infecções sexualmente transmissíveis."], correctIndex: 2 },
  { id: "amrigs_2025_046", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 28 anos, corrimento vaginal, odor fétido e prurido. Ao exame especular: corrimento acinzentado, fluido e homogêneo, aderido às paredes da vagina. pH vaginal 5,0. Teste de aminas positivo. O diagnóstico mais provável e o tratamento preconizado são, respectivamente:", options: ["candidíase vaginal – fluconazol 150mg ao dia, VO – 3 dias", "vaginose bacteriana – secnidazol 2g, VO – 1 dia", "tricomoníase – metronidazol 2g, dose única, VO – 1 dia", "vaginite aeróbica – clindamicina creme vaginal 2% – 14 dias"], correctIndex: 1 },
  { id: "amrigs_2025_047", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 55 anos, no climatério, sintomas vasomotores moderados a graves há 2 anos, impactando qualidade de vida e sono. Opta por não utilizar terapia hormonal, sem contraindicações médicas para outras intervenções. Assinale a recomendação correta baseada em evidências sobre o manejo não hormonal dos fogachos.", options: ["Recomendar medicina herbal chinesa como primeira linha para reduzir a frequência dos fogachos, devido à sua eficácia comprovada em revisões sistemáticas.", "Indicar terapia cognitivo-comportamental, que demonstrou redução significativa dos sintomas vasomotores em ensaios clínicos e é recomendada por diretrizes internacionais.", "Prescrever acupuntura como tratamento principal, dado que revisões sistemáticas confirmaram sua eficácia sustentada no controle dos fogachos, inclusive em longo prazo.", "Sugerir técnicas de relaxamento, como yoga ou tai chi, como primeira linha de tratamento, pois estudos mostraram melhora consistente nos sintomas vasomotores."], correctIndex: 1 },
  { id: "amrigs_2025_048", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 28 anos, dismenorreia intensa, progressiva, e dispareunia nos últimos anos, sintomas pioram durante o fluxo menstrual (suspeita de endometriose). Qual é a melhor abordagem inicial, considerando alívio dos sintomas e preservação da fertilidade?", options: ["Tratamento empírico com progestogênios contínuos, sem necessidade de confirmação diagnóstica por laparoscopia.", "Uso de análogos do GnRH como primeira linha de tratamento para reduzir os níveis de estrogênio.", "Realização de laparoscopia para confirmação diagnóstica e tratamento cirúrgico imediato.", "Uso de contraceptivos com pausa de 7 dias, após laparoscopia cirúrgica."], correctIndex: 0 },
  { id: "amrigs_2025_049", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 25 anos, hirsutismo e acne de progressão lenta, ciclos menstruais irregulares, preocupada com fertilidade futura. Sem sinais de virilização, Ferriman-Gallwey 7, IMC 26. USG pélvica e renal normais. TSH, prolactina, TOTG e 17-OH-progesterona normais (SOP). Qual é a melhor abordagem inicial, considerando alívio dos sintomas e preservação da fertilidade?", options: ["Indicar o uso de contraceptivos hormonais combinados como primeira linha de tratamento para reduzir os níveis de androgênios e regular os ciclos menstruais.", "Iniciar tratamento com metformina para melhorar a resistência à insulina e potencialmente regular os ciclos menstruais.", "Dosar androgênios livres para investigar a presença de ovários policísticos ou tumores produtores de androgênios.", "Indicar o uso de antiandrogênios, como a espirolactona, como primeira linha de tratamento para reduzir os sintomas de hiperandrogenismo."], correctIndex: 0 },
  { id: "amrigs_2025_050", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 30 anos, bypass gástrico há 2 meses, IMC de 30 para 26. Planeja engravidar em 1 ano, precisando de opção segura até lá. Fluxo menstrual aumentado sem causa identificável, história de trombose venosa no passado, assintomática no momento. Qual é o melhor método anticoncepcional, considerando eficácia e segurança pós-cirurgia bariátrica?", options: ["Contraceptivos orais combinados de baixa dosagem.", "Sistema intrauterino liberador de levonorgestrel.", "Adesivo contraceptivo.", "Medroxiprogesterona injetável, pois a fertilidade retorna 2 meses após a pausa."], correctIndex: 1 },
  { id: "amrigs_2025_051", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Primigesta, 28 anos, 40 semanas e 2 dias, trabalho de parto. Contrações regulares há 6 horas, intervalos de 3 minutos, duração média 60 segundos. Dilatação cervical 4cm, esvaecimento completo, bolsa íntegra, líquido claro com grumos, estável. Após 4 horas de evolução, dilatação permanece em 4cm apesar da manutenção das contrações regulares. Qual é a conduta mais adequada nesse momento?", options: ["Realizar amniotomia para acelerar o trabalho de parto.", "Administrar ocitocina para aumentar a intensidade das contrações uterinas.", "Diagnosticar como fase latente prolongada e aguardar evolução espontânea.", "Diagnosticar como trabalho de parto estacionado e indicar cesariana imediata."], correctIndex: 2 },
  { id: "amrigs_2025_052", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Puérpera, 25 anos, primípara, 10 dias após parto vaginal sem complicações. Sangramento vaginal em pequena quantidade, coloração amarelada, desconforto perineal leve. Episiorrafia íntegra, sem sinais de infecção ou hematomas. Fundo uterino não palpável no abdome. Afebril e estável. Qual é a conduta mais adequada nesse momento?", options: ["Solicitar hemograma para descartar anemia pós-parto.", "Realizar ultrassonografia pélvica para avaliar involução uterina.", "Tranquilizar a paciente e orientar sobre os cuidados com o períneo e a evolução dos lóquios.", "Prescrever antibiótico para endometrite de grau leve no puerpério."], correctIndex: 2 },
  { id: "amrigs_2025_053", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Puérpera, 26 anos, primípara, terceiro dia após cesariana de urgência (parada de progressão no trabalho de parto). Febre persistente desde o segundo dia pós-parto, 38,8°C, dor abdominal difusa e loquiação fétida. Útero hipoinvoluído e doloroso à palpação. Estável, sem sinais de choque séptico. Qual é a conduta inicial mais adequada?", options: ["Solicitar e aguardar resultados do hemograma e da hemocultura antes de iniciar antibióticos.", "Iniciar antibioticoterapia empírica intravenosa com cobertura para bactérias aeróbias e anaeróbias.", "Realizar USTV para avaliar retenção de restos placentários antes de iniciar o tratamento.", "Prescrever antibioticoterapia oral com ampicilina e acompanhar ambulatorialmente."], correctIndex: 1 },
  { id: "amrigs_2025_054", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Durante a primeira consulta de uma puérpera amamentando exclusivamente há 15 dias, relata dor intensa nos mamilos durante as mamadas, com fissuras bilaterais. Eritema ao redor dos mamilos, sem sinais de infecção. O manejo inicial deve incluir a correção da técnica de amamentação, especialmente no que diz respeito à:", options: ["Pega do bebê e à posição da mãe e do bebê.", "Pega do bebê e à frequência das mamadas.", "Ordenha manual e à frequência das mamadas.", "Ordenha manual e à posição da mãe e do bebê."], correctIndex: 0 },
  { id: "amrigs_2025_055", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante, 28 anos, segundo trimestre, eliminação de segmentos semelhantes a 'fitas brancas' nas fezes, dor abdominal leve e episódios de diarreia. Consumo recente de carne suína malcozida. O exame protoparasitológico confirma a presença de proglótides. Além de orientar medidas de higiene alimentar, qual é, respectivamente, o diagnóstico mais provável e a conduta mais adequada para o manejo inicial dessa paciente?", options: ["Teníase – prescrever albendazol.", "Teníase – prescrever praziquantel.", "Ascaridíase – iniciar albendazol.", "Ascaridíase – iniciar niclosamida."], correctIndex: 1 },
  { id: "amrigs_2025_056", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante, 32 anos, 36 semanas, G3P2 (todos por via vaginal), ausência de movimentos fetais há 3 dias. Altura uterina compatível, ausência de batimentos cardíacos fetais confirmada pela ultrassonografia. Apresentação cefálica, placenta corporal fúndica. Paciente ansiosa, deseja resolução rápida. Sem sinais de infecção ou coagulopatia. Colo uterino desfavorável (índice de Bishop = 4). Qual é a conduta mais adequada?", options: ["Realizar cesariana imediatamente para remoção do feto.", "Optar pela conduta expectante por até 4 semanas.", "Induzir o parto com misoprostol por via vaginal e reavaliar a cada 4 horas.", "Internar a paciente e iniciar a indução do trabalho de parto com ocitocina intravenosa."], correctIndex: 2 },
  { id: "amrigs_2025_057", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante, 29 anos, 41 semanas de gestação, sem doenças, sente o bebê mexer normalmente, cardiotocografia reativa. A ultrassonografia mostra adramnia. O exame do colo do útero mostra que ele ainda está fechado e grosso. Qual é a conduta mais adequada no caso?", options: ["Realizar amnioinfusão.", "Aguardar até completar 42 semanas sem fazer exames.", "Repetir os exames de bem-estar fetal em 2 dias.", "Interrupção da gestação."], correctIndex: 3 },
  { id: "amrigs_2025_058", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Gestante, 34 anos, 12 semanas de gestação, G3P2, surgimento de lesões pouco dolorosas na região vulvar há 15 dias. Múltiplas lesões papulopustulosas e comedões abertos e fechados na região vulvar e perineal, sem sinais de abscesso, fístulas, confluências ou celulite. O diagnóstico mais provável é de hidradenite supurativa. A conduta inicial mais apropriada deve incluir antibioticoterapia:", options: ["acne vulgar – oral", "acne vulgar – tópica", "hidradenite supurativa – oral", "hidradenite supurativa – tópica"], correctIndex: 3 },
  { id: "amrigs_2025_059", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Psiquiatria", text: "Durante a avaliação de uma paciente no puerpério imediato, observam-se sintomas abruptos de confusão mental, delírios, alucinações auditivas, agitação psicomotora e insônia grave iniciados dentro das primeiras 2 semanas após o parto. Qual é o principal transtorno psiquiátrico relacionado a esse quadro, conhecido como psicose puerperal?", options: ["Esquizofrenia.", "Transtorno depressivo maior.", "Transtorno obsessivo-compulsivo.", "Transtorno bipolar."], correctIndex: 3 },
  { id: "amrigs_2025_060", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Mulher, 32 anos, episódios mensais de intensa irritabilidade, labilidade emocional, fadiga, distúrbios do sono e sensação de descontrole, iniciando cerca de uma semana antes da menstruação e desaparecendo nos primeiros dias do fluxo menstrual. Prejuízo funcional significativo, cíclico, há mais de um ano. Exames excluíram causas ginecológicas, hormonais e hematológicas. Em que fase do ciclo menstrual esse transtorno ocorre mais comumente?", options: ["Folicular.", "Ovulatória.", "Menstrual.", "Lútea."], correctIndex: 3 },
  { id: "amrigs_2025_061", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "Autonomia, privacidade, sigilo e confidencialidade são aspectos a serem considerados na consulta do adolescente. No entanto, a quebra de sigilo é necessária em algumas situações. Entre os casos apresentados a seguir, qual representa uma situação imperativa para a quebra de sigilo?", options: ["Sexo masculino, 13 anos, conflito com identidade de gênero.", "Sexo masculino, 15 anos, uso escalonado de álcool.", "Sexo feminino, 13 anos, início de contracepção oral.", "Sexo feminino, 15 anos, início de atividade sexual."], correctIndex: 1 },
  { id: "amrigs_2025_062", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina, 4 anos, previamente hígida, em coma há 3 horas, chegou à unidade de emergência apresentando postura de decorticação. Analise: I. Corresponde, nos membros superiores, à postura flexora, com adução e flexão de cotovelo, punhos e dedos; nos membros inferiores, à postura extensora. II. Indica lesão supratentorial. III. Pode indicar herniação transtentorial. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 3 },
  { id: "amrigs_2025_063", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Recém-nascido (RN) a termo, 38 semanas, consulta de puericultura com 7 dias de vida. Aleitamento materno exclusivo, mãe com dor ao amamentar e fissuras mamilares. Peso de nascimento 3.140g, peso de alta (48h) 3.020g, peso na consulta 3.090g. São sinais de boa pega e posição: I. Cabeça e tronco do bebê alinhados. II. Bochechas do bebê encovadas. III. Lábio inferior do bebê evertido. IV. Bochechas do bebê tocando o seio. V. Aréola da mãe mais visível acima da boca do bebê. Quais estão corretos?", options: ["Apenas I, II e IV.", "Apenas I, III e V.", "Apenas III, IV e V.", "I, II, III, IV e V."], correctIndex: 1 },
  { id: "amrigs_2025_064", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina, 5 anos, dor e dificuldade para evacuar há mais de 6 meses, fezes de grande calibre que entopem o vaso sanitário. Bom estado geral, eutrófica. Palpa-se grande massa em fossa ilíaca esquerda e roupa íntima com restos fecais. Considerando a principal hipótese diagnóstica, qual deve ser a conduta?", options: ["Administração de probióticos.", "Investigação com ecografia.", "Início de laxantes osmóticos.", "Internação para enemas seriados."], correctIndex: 2 },
  { id: "amrigs_2025_065", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 9 meses, segundo episódio de infecção urinária febril com necessidade de internação. Ecografia prévia (6 meses) normal. Recebeu alta com profilaxia antibiótica diária até resultado dos exames. Uretrocistografia miccional: refluxo vesicoureteral bilateral grau II (RVU-II). Qual deve ser a conduta?", options: ["Modificar profilaxia antibiótica para frequência de 3 vezes na semana.", "Solicitar uretrocistografias miccionais periódicas para controle.", "Indicar correção cirúrgica do refluxo vesicoureteral.", "Suspender profilaxia antibiótica."], correctIndex: 3 },
  { id: "amrigs_2025_066", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menina, 6 meses, previamente hígida, há uma semana com 'espasmos': contrações abruptas seguidas por contrações tônicas de poucos segundos, envolvendo tronco e pescoço, com flexão de braços e pernas, predominantemente na fase de sonolência ou ao despertar. Eletroencefalograma evidenciou hipsarritmia. A paciente apresenta a síndrome:", options: ["dos espasmos epilépticos infantis (síndrome de West).", "de Ohtahara.", "epiléptica neonatal-infantil (familiar) autolimitada.", "de Dravet."], correctIndex: 0 },
  { id: "amrigs_2025_067", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "São fármacos de primeira linha indicados para crianças com crises de ausência típicas:", options: ["Etossuximida, valproato e lamotrigina.", "Etossuximida, valproato e oxcarbazepina.", "Etossuximida, oxcarbazepina e lamotrigina.", "Valproato, lamotrigina e oxcarbazepina."], correctIndex: 0 },
  { id: "amrigs_2025_068", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Menino, 7 anos, previamente hígido, episódio noturno semelhante ao ocorrido há 7 meses (~2 minutos): mãe o encontrou sentado na cama, babando e com fala alterada; depois relatou dormência na língua, lábios, gengiva e bochecha. Exame físico normal à tarde. EEG interictal: ondas agudas bifásicas de alta amplitude seguidas de ondas lentas com projeção nas regiões centro-temporais, exacerbadas durante o sono. O diagnóstico mais provável é:", options: ["Terror noturno.", "Epilepsia rolândica.", "Síndrome de Landau-Kleffner.", "Episódio isquêmico transitório."], correctIndex: 1 },
  { id: "amrigs_2025_069", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança, 8 meses, febril e com rinorreia abundante há três dias. Taquipneica, hipoxemia de 89% em ar ambiente, sibilância difusa na ausculta pulmonar, sem sinais de hipoperfusão tecidual (bronquiolite viral aguda). O manejo inicial dessa criança deve considerar:", options: ["Oxigenação com cateter nasal de baixo fluxo e fração inspirada de oxigênio de 100% inicialmente.", "Antibioticoterapia empírica com ampicilina intravenosa.", "Salbutamol inalado associado a corticosteroide sistêmico.", "Lavagem nasal com cloreto de sódio a 0,9% e oxigenação adequada."], correctIndex: 3 },
  { id: "amrigs_2025_070", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Considerando um caso de desidratação em escolar, de 16kg, associada à diarreia aguda febril tipo disenteria, ainda sem sinais de taquicardia, sem rebaixamento de sensório, nem prolongamento do tempo de enchimento capilar, a correção deve ser feita no(a) ____ e com o insumo denominado ____.", options: ["sala de emergência – soro reidratante oral", "domicílio – soro reidratante oral", "unidade de terapia intensiva – ringer lactato intravenoso", "sala de emergência – soro fisiológico intravenoso"], correctIndex: 0 },
  { id: "amrigs_2025_071", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Adolescente, 13 anos, ingeriu uma cartela de 20 comprimidos de diazepam. Chega à emergência desacordado, eupneico, hipotenso e com escala de coma de Glasgow de 6. A conduta mais efetiva nesse momento, no que diz respeito à resolução do coma, é:", options: ["Proceder à intubação orotraqueal.", "Administrar solução salina hipertônica intravenosa.", "Administrar flumazenil intravenoso.", "Administrar naloxone intravenoso."], correctIndex: 2 },
  { id: "amrigs_2025_072", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Na crise adrenal do lactente em choque séptico, há evidência de hiponatremia e hiperpotassemia. Em relação às complicações graves, a parada cardiorrespiratória associada nesse contexto tem como causa mais plausível:", options: ["A desidratação neuronal da hiponatremia, gerando morte neuronal.", "O edema cerebral da hiperpotassemia, gerando herniação uncal.", "A fibrilação ventricular da hiperpotassemia, gerando ausência de pulso.", "A hipoxemia celular pelo deslocamento da curva de dissociação da hemoglobina para a direita, pela hiponatremia."], correctIndex: 2 },
  { id: "amrigs_2025_073", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "A cetoacidose diabética na criança predispõe ao risco aumentado de morte por edema cerebral, estando frequentemente associado ao(à):", options: ["Insulinização contínua, em vez da intermitente.", "Expansão volêmica cautelosa.", "Utilização de potássio intravenoso superior à sua necessidade diária.", "Rebaixamento de sensório nas primeiras 12 horas do manejo."], correctIndex: 2 },
  { id: "amrigs_2025_074", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Na triagem inicial do paciente politraumatizado pediátrico, a lesão de menor mortalidade, considerando as apresentadas abaixo, é:", options: ["Trauma cervical com ruptura de laringe.", "Pneumotórax aberto.", "Concussão cerebral, levando à crise convulsiva.", "Hipotensão por ruptura gástrica."], correctIndex: 2 },
  { id: "amrigs_2025_076", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Em uma criança vítima de acidente por submersão, a lesão que mais agressivamente deve ser tratada, por estar diretamente relacionada à morbimortalidade nesse tipo de acidente, é a:", options: ["Hipernatremia por afogamento em água salgada.", "Hipoxemia sistêmica.", "Infecção por afogamento em águas contaminadas.", "Obstrução de via aérea pela aspiração de água."], correctIndex: 1 },
  { id: "amrigs_2025_077", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Gestante de 39 semanas chega em franco trabalho de parto ao centro obstétrico. Em sua carteira de pré-natal, consta resultado positivo para triagem de HTLV (teste ELISA) no segundo trimestre gestacional. As demais sorologias eram não reagentes. Qual é a medida mais eficaz para prevenir a infecção do neonato pelo HTLV?", options: ["Indicar parto por cesariana.", "Orientar o clampeamento imediato do cordão umbilical após o nascimento.", "Prescrever zidovudina solução oral nos primeiros 28 dias do neonato.", "Contraindicar o aleitamento materno."], correctIndex: 3 },
  { id: "amrigs_2025_078", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "RN, 8 dias de vida, internado por sífilis congênita, recebendo penicilina cristalina desde o primeiro dia. VDRL sérico 1:4, VDRL no líquor não reagente, líquor com proteínas totais 69mg/dl, 5 leucócitos/mm³ e glicose 60mg/dl. Raio X de ossos longos normal. Enfermagem informa perda do acesso vascular intravenoso periférico. Qual é a conduta mais adequada para a finalização do tratamento?", options: ["Completar o tratamento com penicilina benzatina em dose única.", "Completar o tratamento com penicilina procaína intramuscular até o 10º dia de tratamento.", "Completar o tratamento com penicilina procaína intramuscular até o 14º dia de tratamento.", "Solicitar acesso venoso central e completar o tratamento com penicilina cristalina até o 10º dia de tratamento."], correctIndex: 1 },
  { id: "amrigs_2025_079", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Em relação ao tratamento farmacológico com psicoestimulantes no Transtorno de Déficit de Atenção e Hiperatividade (TDAH), assinale a alternativa correta.", options: ["A interrupção do uso da medicação durante os fins de semana é recomendada para todos os pacientes com TDAH, a fim de minimizar efeitos adversos a longo prazo.", "O tratamento com estimulantes aumenta o risco de desenvolvimento de transtornos por uso de substâncias.", "Para crianças, a melhora dos sintomas com psicoestimulantes tende a ser restrita ao ambiente escolar, não havendo benefício significativo em outros contextos da vida da criança.", "Além da redução dos sintomas de desatenção e hiperatividade, os psicoestimulantes repercutem positivamente sobre irritabilidade, autoestima, relações interpessoais e funcionamento cognitivo."], correctIndex: 3 },
  { id: "amrigs_2025_080", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Em relação ao transtorno de oposição desafiante, analise: I. Caracteriza-se por padrão de humor raivoso e/ou irritável, de comportamento questionador e/ou desafiante ou índole vingativa, com duração de pelo menos 6 meses. II. Considerando que, em geral, os sintomas são mais evidentes nas interações com adultos ou pares que o indivíduo conhece bem, eles podem não ficar tão evidentes no exame clínico. III. A presença de sintomas do transtorno em múltiplos contextos é um indicativo de gravidade. IV. Os sintomas de humor raivoso e/ou irritável respondem pela maior parte do risco para transtorno da conduta. Quais estão corretas?", options: ["Apenas I e II.", "Apenas III e IV.", "Apenas I, II e III.", "I, II, III e IV."], correctIndex: 2 },
  { id: "amrigs_2025_081", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Sobre a organização da Atenção Primária à Saúde (APS), assinale a alternativa correta.", options: ["A consolidação da APS se dá pela efetiva coordenação do cuidado, que demanda articulação longitudinal entre a atenção primária e os demais pontos da rede assistencial.", "A inserção de equipes de Estratégia Saúde da Família (ESF) na APS visa restringir o acesso à atenção especializada como forma de reduzir os custos hospitalares e exames de alta complexidade.", "A abordagem centrada na pessoa na APS prioriza a intervenção biomédica, independentemente da compreensão das condições socioambientais dos pacientes.", "A gestão da APS deve ser organizada de forma verticalizada e centralizada para assegurar a padronização dos serviços prestados nas unidades locais."], correctIndex: 0 },
  { id: "amrigs_2025_082", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Maria Joana, 62 anos, diagnosticada com enfisema pulmonar, é acompanhada há 5 anos pela mesma equipe da Estratégia Saúde da Família, sentindo-se segura com profissionais que conhecem seu histórico. Recebe visitas domiciliares e tem cuidado articulado com a rede especializada, sem perder o vínculo com a equipe. Participa de grupos educativos sobre cessação do tabagismo. Com base nos atributos da APS, a situação descrita exemplifica, principalmente:", options: ["Integralidade, regionalização e territorialização.", "Universalidade, longitudinalidade e equidade.", "Equidade, acesso e universalidade.", "Longitudinalidade, integralidade e coordenação."], correctIndex: 3 },
  { id: "amrigs_2025_083", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "No contexto da atenção domiciliar vinculada à APS, analise: I. O cuidado domiciliar pode ser indicado para indivíduos com limitações temporárias ou permanentes na mobilidade, visando promover reabilitação e manutenção da autonomia funcional. II. A internação domiciliar destina-se a pacientes com quadro clínico instável, que necessitem de suporte ventilatório avançado ou monitorização intensiva, substituindo o ambiente hospitalar. III. O acompanhamento domiciliar é direcionado a pacientes que requerem intervenções periódicas ou paliativas, incluindo tratamento crônico avançado ou limitações para deslocamento. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 1 },
  { id: "amrigs_2025_084", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em relação aos Conselhos de Saúde, analise: I. São instâncias deliberativas e permanentes do SUS em cada esfera de governo. II. Sua composição deve garantir paridade entre representantes do governo e da sociedade civil. III. Têm como uma de suas atribuições aprovar o Plano Municipal de Saúde. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 3 },
  { id: "amrigs_2025_085", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Marta, 43 anos, hipertensa e diabética, mudou de endereço dentro do mesmo município e passou a procurar atendimento em outra UBS, sem acesso ao histórico clínico nem reconhecimento do vínculo anterior. Ao procurar uma UPA por descompensação, exames foram repetidos e o plano terapêutico reiniciado a partir de informações parciais, com sensação de que 'os serviços não se comunicam'. Entre os princípios do SUS, a situação descrita reflete, sobretudo, uma violação do princípio da:", options: ["Equidade – ao não priorizar o cuidado da paciente conforme suas vulnerabilidades clínicas.", "Universalidade – ao condicionar o acesso da paciente ao vínculo territorial anterior.", "Integralidade – ao fragmentar a atenção e dificultar o fluxo contínuo e articulado de cuidado.", "Regionalização – ao não garantir a referência assistencial entre os pontos de atenção do território."], correctIndex: 2 },
  { id: "amrigs_2025_086", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "A consulta embasada no Método Clínico Centrado na Pessoa (MCCP) apresenta alguns componentes. Analise: 1. Fortalecer a relação médico-paciente. 2. Conhecer o contexto do paciente. 3. Construir um entendimento acerca do problema e do que precisa ser feito. 4. Focalizar os aspectos objetivos da doença, como sinais e sintomas (não constitui componente isolado do MCCP). O resultado da somatória dos números correspondentes aos componentes corretos é:", options: ["05.", "06.", "08.", "10."], correctIndex: 1 },
  { id: "amrigs_2025_087", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "No território de uma equipe de ESF, Ana, 38 anos, foi diagnosticada com depressão moderada durante consulta com o enfermeiro, com sintomas persistentes há mais de 6 meses, dificuldades familiares e desesperança, sem ideação suicida. Após acolhimento e escuta qualificada, o enfermeiro iniciou plano de cuidado e encaminhou para consulta médica, que confirmou o diagnóstico e iniciou antidepressivo, com acompanhamento longitudinal conjunto após 4 semanas. Assinale a alternativa correta sobre a condução do caso.", options: ["O enfermeiro extrapolou suas atribuições ao conduzir a escuta inicial e propor plano de cuidado antes da consulta médica.", "A condução do caso demonstra inadequação ao modelo da ESF, pois o enfermeiro não pode atuar em condições de saúde mental.", "A atuação do enfermeiro está de acordo com suas competências, incluindo acolhimento, escuta e organização do processo de cuidado.", "O médico não deveria prescrever antidepressivos na APS sem avaliação de um profissional da saúde mental da atenção especializada."], correctIndex: 2 },
  { id: "amrigs_2025_088", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Durante a primeira consulta de pré-natal, no primeiro trimestre da gestação, uma gestante de 35 anos apresenta caderneta vacinal desatualizada, nunca tendo recebido vacina dTpa (difteria, tétano e coqueluche acelular) nem contra hepatite B. Qual das condutas a seguir é a mais apropriada?", options: ["A dTpa deve ser aplicada imediatamente, para garantir proteção precoce contra coqueluche neonatal.", "A hepatite B deve ser iniciada no segundo trimestre, pois não é segura no primeiro trimestre.", "A dTpa deve ser aplicada a partir da 20ª semana de gestação, mesmo que seja a primeira dose da série.", "Nenhuma vacina deve ser administrada no primeiro trimestre da gestação, por risco teratogênico ao feto."], correctIndex: 2 },
  { id: "amrigs_2025_089", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em relação às doenças e agravos de notificação compulsória imediata no território brasileiro, assinale a alternativa que apresenta situações que obrigatoriamente exigem comunicação às autoridades de saúde em até 24 horas, independentemente de confirmação laboratorial.", options: ["Malária adquirida em áreas endêmicas; febre amarela silvestre.", "Óbito por arboviroses; detecção de infecção por zika vírus em gestante.", "Hanseníase multibacilar; leptospirose em zona rural.", "Hanseníase virchowiana; infecção pelo vírus influenza A."], correctIndex: 1 },
  { id: "amrigs_2025_090", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Analise as assertivas relativas aos indicadores de desempenho do Programa Previne Brasil: I. São avaliadas apenas as vacinas da pentavalente e da poliomielite inativada, aplicadas até os 12 meses de idade, no indicador de cobertura vacinal. II. Mulheres entre 25 e 64 anos são elegíveis para o indicador de exame citopatológico do colo do útero. III. O indicador de saúde bucal da gestante considera a proporção de gestantes com pelo menos dois atendimentos odontológicos completos durante o pré-natal. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 0 },
  { id: "amrigs_2025_091", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "Durante a primeira consulta, um cirurgião plástico afirma à paciente interessada em abdominoplastia: 'Com a técnica que eu uso, garanto que você ficará com o abdome completamente liso, sem nenhuma cicatriz visível'. A paciente assina o termo de consentimento informado e realiza a cirurgia, mas apresenta cicatrizes evidentes e discreta flacidez residual, acionando o Conselho Regional de Medicina. Assinale a alternativa correta.", options: ["O médico cometeu infração ética, pois é vedado prometer resultados, mesmo com boa técnica e assinatura do consentimento.", "A assinatura do consentimento informado descaracteriza infração ética, desde que a técnica tenha sido realizada adequadamente.", "A infração ética decorre da frustração da paciente com o resultado obtido, e não da promessa verbal feita pelo médico.", "A promessa de resultado pode ser considerada infração apenas se for comprovado que o médico omitiu os riscos e limitações do procedimento."], correctIndex: 0 },
  { id: "amrigs_2025_092", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Um estudo observacional transversal com 2.000 homens adultos avaliou níveis séricos de vitamina D e testosterona, encontrando correlação positiva estatisticamente significativa (p<0,01). Um médico afirmou em congresso: 'Está claro que a reposição de vitamina D aumenta os níveis de testosterona nos homens'. Sobre essa afirmação, é correto afirmar que:", options: ["A correlação identificada sugere causalidade, pois é estatisticamente significativa.", "O delineamento transversal do estudo não permite afirmar relação causal entre as variáveis.", "O p-valor <0,01 confirma que a vitamina D regula a produção testicular de testosterona.", "A associação entre as variáveis confirma que a reposição de vitamina D é indicada para todos os homens com baixa testosterona."], correctIndex: 1 },
  { id: "amrigs_2025_093", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Um pronto-socorro recebe um adolescente febril, com cefaleia intensa, rigidez de nuca e vômitos. Diante da suspeita de meningite bacteriana, é realizado teste laboratorial rápido, cuja razão de verossimilhança negativa (LR-) é de 0,01. O resultado do teste foi negativo. A probabilidade pré-teste estimada era de 40%. Qual conduta e interpretação é mais adequada?", options: ["Iniciar antibioticoterapia empírica imediatamente, pois a gravidade da doença exige tratamento mesmo com baixa probabilidade.", "Confiar no teste e descartar meningite bacteriana, pois o resultado negativo reduz fortemente a probabilidade pós-teste.", "Repetir o teste para confirmar o resultado, já que a sensibilidade foi baixa.", "Concluir que o teste é pouco útil, pois seu valor preditivo negativo é baixo em contextos de alta suspeita."], correctIndex: 1 },
  { id: "amrigs_2025_094", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em um estudo sobre efeitos adversos gastrointestinais de um novo AINE, após 12 meses, 10% dos usuários do novo AINE desenvolveram úlcera gástrica documentada por endoscopia, enquanto 5% dos pacientes do grupo controle (AINE clássico) apresentaram o mesmo desfecho. O número necessário para causar dano (NNH) é, aproximadamente:", options: ["05.", "10.", "20.", "50."], correctIndex: 2 },
  { id: "amrigs_2025_095", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Durante a avaliação de um teste sorológico para hepatite B, pesquisadores observaram Valor Preditivo Positivo (VPP) de 40% em campanhas populacionais abertas, mas de 85% quando aplicado exclusivamente em grupos de risco, mantendo-se inalteradas a sensibilidade e a especificidade do teste. Assinale a alternativa correta sobre o comportamento do VPP.", options: ["O aumento do VPP nos grupos de risco decorre da modificação da acurácia do teste em subgrupos com maior carga viral média e maior expressão antigênica.", "A variação do VPP resulta da interação entre sensibilidade e prevalência, já que populações de maior risco apresentam também maior proporção de falsos-negativos.", "O comportamento do VPP reflete a dependência direta do valor preditivo em relação à prevalência da doença nos grupos avaliados, apesar de a sensibilidade e a especificidade serem constantes.", "A diferença entre os VPPs é consequência da influência do viés de verificação, já que casos positivos nos grupos de risco são mais frequentemente confirmados por exames moleculares."], correctIndex: 2 },
  { id: "amrigs_2025_097", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Em um ensaio clínico randomizado sobre uso de estatinas em prevenção primária, 15% dos pacientes do grupo controle passaram a tomar estatina por conta própria. Os autores mantiveram esses pacientes no grupo original da randomização. É correto afirmar que essa decisão:", options: ["Introduz viés de aferição.", "Distorce os resultados, tornando-os estatisticamente nulos.", "É compatível com a análise por intenção de tratar.", "Exige reclassificação dos pacientes por grupo de exposição real."], correctIndex: 2 },
  { id: "amrigs_2025_098", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Pesquisadores desenharam um estudo para avaliar a associação entre tabagismo e risco de parto prematuro. Gestantes no primeiro trimestre foram classificadas como fumantes ou não fumantes e acompanhadas com visitas regulares e coleta sistemática de dados até o desfecho da gestação, comparando-se a taxa de partos prematuros entre os dois grupos. Trata-se de um:", options: ["Estudo de caso-controle.", "Estudo transversal.", "Ensaio clínico controlado.", "Estudo de coorte."], correctIndex: 3 },
  { id: "amrigs_2025_099", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Psiquiatria", text: "Mulher, 55 anos, viúva, tristeza persistente, perda de interesse, fadiga, distúrbios do sono, hiporexia e sentimentos de inutilidade há cerca de 2 meses (episódio depressivo maior moderado, sem ideação suicida ativa). Iniciada amitriptilina, com ajuste até 75mg/dia à noite. Após 3 semanas, relata efeitos colaterais. Relacione a Coluna 1 (1. Efeito anti-histamínico; 2. Antagonismo α1-adrenérgico; 3. Efeito anticolinérgico) à Coluna 2: (Boca seca intensa e visão turva para leitura.) (Tontura ao se levantar rapidamente da cama, com hipotensão postural ao exame.) (Episódios de constipação intestinal, com intervalos de até 4 dias sem evacuar.) (Sonolência diurna, dificuldade para manter-se acordada e aumento do apetite.) A ordem correta, de cima para baixo, é:", options: ["3 – 2 – 3 – 1.", "3 – 1 – 1 – 2.", "1 – 2 – 3 – 1.", "2 – 1 – 3 – 2."], correctIndex: 0 },
  { id: "amrigs_2025_100", banca: "AMRIGS", cycle: "Ciclo Clínico", subject: "Medicina de Família", text: "Homem, 42 anos, na atenção primária, relata fumar cerca de 20 cigarros ou mais por dia há mais de 15 anos, forte necessidade de fumar ao acordar, já tentou parar 2 vezes com recaída por irritabilidade/ansiedade. Decidido a parar nas próximas semanas, sem data definida. Escore de Fagerström 7. Analise: I. Na data escolhida para parar de fumar, deve-se iniciar imediatamente o uso de adesivo de nicotina de 21mg/dia, associando bupropiona 150mg 1 vez ao dia por 3 dias, depois 2 vezes ao dia. II. A combinação de abordagens comportamentais com a farmacoterapia é o formato mais útil para os pacientes que estão tentando parar de fumar. III. Como segunda linha, clonidina e nortriptilina são opções terapêuticas para cessação do tabagismo, embora com maior perfil de efeitos adversos. Quais estão corretas?", options: ["Apenas I e II.", "Apenas I e III.", "Apenas II e III.", "I, II e III."], correctIndex: 2 },
];
